import math

def equipes_necessarias(total_familias, capacidade_equipe):
    return math.ceil(total_familias / capacidade_equipe)

print(equipes_necessarias(125, 18))   # 7
print(equipes_necessarias(40, 10))     # 4

from math import sqrt

def distancia(x1, y1, x2, y2):
    return sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2)

print(distancia(0, 0, 3, 4))   # 5.0
